        if (leftVal > rightVal) {
            result[position] = leftVal * leftVal;
            left++;
        } else {
            result[position] = rightVal * rightVal;
            right--;
        }
        position--;
    }
    return result;
}

int* sortedSquares(int* nums, int numsSize, int* returnSize) {
    *returnSize = numsSize;
    int* res = (int*)malloc(numsSize * sizeof(int));
    int l = 0, r = numsSize - 1, p = numsSize - 1;
    while (l <= r) {
        int ls = nums[l]*nums[l], rs = nums[r]*nums[r];
        if (ls > rs) { res[p--] = ls; l++; }
        else         { res[p--] = rs; r--; }
    }
    return res;
}

