typedef struct { int key; int val; } Entry;
int* twoSum(int* nums, int numsSize, int target, int* returnSize) {
    *returnSize = 2;
    int* result = (int*)malloc(2 * sizeof(int));
    Entry* table = (Entry*)calloc(numsSize * 2, sizeof(Entry));
    int cap = numsSize * 2;
    for (int i = 0; i < numsSize; i++) {
        int need = target - nums[i];
        int h = ((need % cap) + cap) % cap;
        while (table[h].val && table[h].key != need) h = (h + 1) % cap;
        if (table[h].val) { result[0] = table[h].val - 1; result[1] = i; free(table); return result; }
        h = ((nums[i] % cap) + cap) % cap;
        while (table[h].val && table[h].key != nums[i]) h = (h + 1) % cap;
        table[h].key = nums[i]; table[h].val = i + 1;
    }
    free(table); return result;
}

